  ariaLabel="Scroll to comments"
  onclick="scrollToCommentSection()"
  class="hide"
/>

<script is:inline>
  window.scrollToCommentSection = function () {
    const commentSection = document.getElementById("post-comments");
    if (!commentSection) return;

    commentSection.scrollIntoView({
      behavior: "smooth",
      block: "start",
    });
  };

  function updateCommentButtonVisibility() {
    const btn = document.getElementById("back-to-comment-btn");
    const commentSection = document.getElementById("post-comments");
    if (!btn) return;

    // No comment section on current page: keep hidden.
    if (!commentSection) {
      btn.style.display = "none";
      btn.classList.add("hide");
      return;
    }

    btn.style.display = "";
    btn.classList.remove("hide");
  }

  updateCommentButtonVisibility();
  setTimeout(updateCommentButtonVisibility, 0);
  requestAnimationFrame(updateCommentButtonVisibility);

  document.addEventListener("astro:page-load", updateCommentButtonVisibility);
  document.addEventListener("swup:contentReplaced", updateCommentButtonVisibility);
  document.addEventListener("swup:enable", updateCommentButtonVisibility);
</script>

import type { Element, ElementContent, Root } from 'hast'
import { visit } from 'unist-util-visit'

const headingRank = (tag: string) => /^h[1-6]$/.test(tag)

// Add # link to headings
export default function rehypeAutolinkHeadings({
  properties = { ariaHidden: 'true', tabIndex: -1 },
  behavior = 'prepend',
  content = { type: 'text', value: '#' } as ElementContent
} = {}) {
  return (tree: Root) => {
    visit(tree, 'element', (node: Element) => {
      if (headingRank(node.tagName) && node.properties?.id) {
        const link: Element = {
          type: 'element',
          tagName: 'a',
          properties: { ...properties, href: `#${node.properties.id.toString()}` },
          // children: Array.isArray(content) ? content : [content]
          children: Array.isArray(content)
            ? content
            : typeof content === 'object' && content.type
              ? [content]
              : []
        }

        if (!['wrap', 'prepend', 'append'].includes(behavior)) {
          throw new Error(`Invalid behavior: ${behavior}`)
        }

        node.children = node.children || []
        if (behavior === 'wrap') {
          node.children = [link]
        } else if (behavior === 'prepend') {
          node.children.unshift(link)
        } else if (behavior === 'append') {
          node.children.push(link)
        }
      }
    })
  }
}

import { visit } from 'unist-util-visit'

export function remarkEmbed() {
  return function (tree) {
    visit(tree, (node) => {
      if (node.type === 'leafDirective') {
        if (!['youtube', 'bilibili', 'codepen'].includes(node.name)) return

        const data = node.data || (node.data = {})
        const attributes = node.attributes || {}
        const id = attributes.id

        if (!id) return

        data.hName = 'iframe'
        switch (node.name) {
          case 'youtube':
            data.hProperties = {
              class: 'video',
              title: 'YouTube Video Player',
              src: `https://www.youtube.com/embed/${id}`,
              frameBorder: 0,
              allow:
                'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share',
              allowFullScreen: true,
              loading: 'lazy',
            }
            break
          case 'bilibili':
            data.hProperties = {
              class: 'video',
              title: 'Bilibili Video Player',
              src: `//player.bilibili.com/player.html?isOutside=true&bvid=${id}`,
              frameBorder: 0,
              allowFullScreen: true,
              loading: 'lazy',
            }
            break
          case 'codepen':
            data.hProperties = {
              class: 'codepen',
              title: 'CodePen Embed',
              src: `https://codepen.io/${attributes.author}/embed/${id}`,
              frameBorder: 0,
              allowFullScreen: true,
              loading: 'lazy',
            }
            break
        }
      }
    })
  }
}

import {event} from '../panzoom/client_utils'

function init_gallery_clicks(container){
    if(container.getAttribute("data-state") != "init"){
        return
    }
    const collapsible = container.querySelector(".collapsible")
    const content = container.querySelector(".content")
    collapsible.onclick = ()=>{
        content.classList.toggle("expanded")
        if (content.classList.contains("expanded")){
            //*2 speeds up the animation but resolves the resize problem without actively watching the resize
            content.style.maxHeight = content.scrollHeight*2 + "px";
            collapsible.textContent = "Click to close"
        } else {
            content.style.maxHeight = null;
            collapsible.textContent = "Click to expand"
        }
        console.log(content.style.maxHeight)
    }

    //item open modal
    const itemimages = container.querySelectorAll(".itemimage")
    const items = [...itemimages]
    for(let el in items){
        items[el].onclick = (e)=>{
            const modal = e.target.parentElement.querySelector(".modal-background")
            event(modal,"open")
        }
    }

}

function init(){
    const containers = document.querySelectorAll(".container.gallery")
    containers.forEach(container => {
        init_gallery_clicks(container)
    })
}

document.addEventListener('DOMContentLoaded', init, false);

