export const searchQuery = z
	.object({
		q: z.string().min(1),
		collections: z.string().optional(),
		status: z.string().optional(),
		locale: localeCode.optional(),
		limit: z.coerce.number().int().min(1).max(100).optional(),
	})
	.meta({ id: "SearchQuery" });

export const searchSuggestQuery = z
	.object({
